import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"钥令列表","description":"","frontmatter":{},"headers":[],"relativePath":"key-orders/list.md","filePath":"zh/key-orders/list.md","lastUpdated":1775394001000}'),s={name:"key-orders/list.md"};function o(l,t,n,h,i,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="钥令列表" tabindex="-1">钥令列表 <a class="header-anchor" href="#钥令列表" aria-label="Permalink to &quot;钥令列表&quot;">​</a></h1><p>钥令 (Key Command) 是守密人的独属战斗能力，通过银钥能量驱动。银钥能量达到1000时可释放已装备的钥令，每回合可使用1次（纯混沌编成时2次）。</p><div class="tip custom-block"><p class="custom-block-title">银钥觉醒 (v2.0新增)</p><p>银钥能量满时，可额外选择「银钥觉醒」将指定唤醒体的灵知觉醒卡以「保留」状态置入手中。每回合可触发1次，与钥令独立冷却。</p></div><h2 id="通用钥令" tabindex="-1">通用钥令 <a class="header-anchor" href="#通用钥令" aria-label="Permalink to &quot;通用钥令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>钥令名称</th><th>界域亲和</th><th>类型</th><th>效果</th><th>获取方式</th></tr></thead><tbody><tr><td>鼠辈智慧 (Mouse Wisdom)</td><td>通用</td><td>资源</td><td>获得3点算力</td><td>通关主线第二章2-15</td></tr><tr><td>小小心愿 (Little Wish)</td><td>通用</td><td>狂气</td><td>选择1名唤醒体，使其获得35点狂气</td><td>主线剧情</td></tr><tr><td>酒馆之门 (The Tavern Door)</td><td>通用</td><td>抽牌</td><td>将1张「莉雅的硬币」(获得2点算力并抽2张牌)置入弃牌堆</td><td>通关多维联动「逆流...」</td></tr><tr><td>注射防卫 (Injection Guard)</td><td>通用</td><td>防御</td><td>防御/护盾相关效果</td><td>主线剧情</td></tr><tr><td>永世执念 (Eternal Obsession)</td><td>通用</td><td>力量爆发</td><td>获得25%临时暴击率和7点临时力量。首领战中若本回合未打出手牌，触发1次死亡抵抗；成功则获得138点护盾(仅1次)</td><td>主线剧情</td></tr><tr><td>不平等交换 (Unequal Exchange)</td><td>通用</td><td>工具</td><td>v1.1移除「下回合开始时少抽1张牌」的副作用</td><td>主线剧情</td></tr><tr><td>仲夏之梦 (A Momentary Dream)</td><td>通用</td><td>抽牌工具</td><td>抽1张牌，如果抽到指令卡或灵知觉醒，将其算力消耗变为0，否则弃掉并重复。本场战斗内界域精通永久提高25点</td><td>主线剧情</td></tr><tr><td>最后的誓言 (The Final Oath)</td><td>通用</td><td>力量爆发</td><td>获得23点临时力量，25%临时暴击率。首领战中如果本回合尚未打出手牌，额外触发1次死亡抵抗；成功则获得1层屏障(仅1次)</td><td>扩展计划/剧情解锁</td></tr><tr><td>回溯的终末 (Retrospective End)</td><td>通用</td><td>卡牌复制</td><td>将上回合打出的最后1张非衍生指令卡的原始复制置入手中，算力消耗-1，附加消耗与虚无</td><td>扩展计划/剧情解锁</td></tr><tr><td>不朽的葬仪 (Immortal Funeral Rites)</td><td>通用</td><td>狂气献祭</td><td>所有唤醒体获得12点狂气，下回合开始获得5%最大生命的献祭</td><td>扩展计划/剧情解锁</td></tr><tr><td>岁末花火 (Year-End Fireworks)</td><td>通用</td><td>强效技能</td><td>选择一名友方，使其临时强效+1并获得自身2张不同的技能，回合结束时弃掉所有手牌</td><td>v1.1.11更新新增</td></tr><tr><td>深宅往事 (Manor Memories)</td><td>通用</td><td>减益</td><td>选择一名友方，对其他友方和全体敌方施加1层「痴醉」(指令卡、狂气爆发造成的伤害/治疗/护盾效果降低10%，无法驱散，上限2层)</td><td>剧情解锁</td></tr><tr><td>泣血的圣心 (Bleeding Sacred Heart)</td><td>通用</td><td>抽牌暴击</td><td>抽1张算力消耗最高的「技能」，使其获得预备</td><td>剧情/活动解锁</td></tr></tbody></table><h2 id="界域专属钥令" tabindex="-1">界域专属钥令 <a class="header-anchor" href="#界域专属钥令" aria-label="Permalink to &quot;界域专属钥令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>钥令名称</th><th>界域亲和</th><th>类型</th><th>效果</th><th>界域加成</th><th>获取方式</th></tr></thead><tbody><tr><td>咆哮的血与沙 (Roar of Blood and Sand)</td><td><span class="realm-badge realm-caro">血肉</span></td><td>狂气力量</td><td>失去10%当前生命，选择1名唤醒体使其获得25点狂气，获得12点力量</td><td>血肉：额外使胚胎融合度+25</td><td>扩展计划/剧情解锁</td></tr><tr><td>蚀骨的拥抱 (Corrosive Embrace)</td><td><span class="realm-badge realm-aequor">深海</span></td><td>资源防御</td><td>获得1点算力，下回合开始获得75点护盾</td><td>深海：不获得护盾，改为生成1条触腕</td><td>扩展计划/剧情解锁</td></tr><tr><td>短暂的永恒 (Brief Eternity)</td><td><span class="realm-badge realm-ultra">超维</span></td><td>卡牌生成</td><td>选择1名唤醒体，将其2张「打击」与「防御」置入手中，附加消耗与虚无</td><td>超维：额外获得15点临时力量与4点临时戒备</td><td>扩展计划/剧情解锁</td></tr><tr><td>灰雾面容 (Ashen Mist Visage)</td><td><span class="realm-badge realm-ultra">超维</span></td><td>暴击抽牌</td><td>本场战斗内暴击率永久提高5%，将1张「灵感」置入手中</td><td>超维(超维回合中)：额外将1张灵感置入手中</td><td>扩展计划/剧情解锁</td></tr><tr><td>湖畔回眸 (Lakeside Glance)</td><td><span class="realm-badge realm-caro">血肉</span></td><td>防御毒素</td><td>获得60点护盾，对所有敌人施加相当于25%我方护盾的中毒</td><td>血肉：损失生命越多中毒量越高，至多50%护盾值</td><td>扩展计划/剧情解锁</td></tr><tr><td>玫瑰的胜利 (Victory of the Rose)</td><td><span class="realm-badge realm-caro">血肉</span></td><td>治疗力量</td><td>回复45点生命。生命低于25%时，获得与回复量相等的临时力量</td><td>血肉：回复量+50%，不再直接回血，储存至猩红熔炉</td><td>扩展计划/剧情解锁</td></tr><tr><td>奥瑞塔的宝藏 (Aurita&#39;s Treasure)</td><td><span class="realm-badge realm-aequor">深海</span></td><td>抽牌触腕</td><td>将抽牌堆中算力最低的3张置入手中</td><td>深海：额外使触腕伤害提高4~8点</td><td>扩展计划/剧情解锁</td></tr></tbody></table><h2 id="配队推荐" tabindex="-1">配队推荐 <a class="header-anchor" href="#配队推荐" aria-label="Permalink to &quot;配队推荐&quot;">​</a></h2><table tabindex="0"><thead><tr><th>队伍类型</th><th>推荐钥令</th><th>说明</th></tr></thead><tbody><tr><td>深海触腕队</td><td>奥瑞塔的宝藏、蚀骨的拥抱</td><td>触腕生成和触腕伤害加成</td></tr><tr><td>血肉胚胎/融合队</td><td>咆哮的血与沙、湖畔回眸、玫瑰的胜利</td><td>胚胎融合度、生命损失联动、猩红熔炉储存</td></tr><tr><td>超维刷牌队</td><td>短暂的永恒、灰雾面容</td><td>额外手牌生成、灵感卡助力超维回合</td></tr><tr><td>力量爆发队</td><td>永世执念、最后的誓言</td><td>大幅力量增益与暴击率</td></tr><tr><td>狂气速充队</td><td>不朽的葬仪、咆哮的血与沙、小小心愿</td><td>快速充满狂气释放狂气爆发</td></tr><tr><td>通用/新手</td><td>仲夏之梦、鼠辈智慧、酒馆之门</td><td>算力补充和抽牌，适用于所有队伍</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">数值说明</p><p>以上数值以守密人等级60为准。当前共有20个钥令可收集。</p></div>',10)])])}const b=d(s,[["render",o]]);export{p as __pageData,b as default};
